use fastly::http::{header, Method, StatusCode};
use fastly::{mime, Error, Request, Response};

const BACKEND_API: &str = "api_backend";
const BACKEND_STATIC: &str = "static_backend";
const BACKEND_AUTH: &str = "auth_backend";

#[fastly::main]
fn main(mut req: Request) -> Result<Response, Error> {
    let path = req.get_path();
    let method = req.get_method();

    let route_result = match (method, path) {
        (Method::GET | Method::POST | Method::PUT | Method::DELETE, path) if path.starts_with("/api/") => {
            route_to_api(req)
        }
        (Method::POST, "/auth/login") | (Method::POST, "/auth/register") => {
            route_to_auth(req)
        }
        (Method::GET, path) if path.starts_with("/static/") || path.ends_with(".css") || path.ends_with(".js") || path.ends_with(".png") => {
            route_to_static(req)
        }
        (Method::GET, "/health") => {
            Ok(Response::from_status(StatusCode::OK)
                .with_body_text_plain("OK\n"))
        }
        _ => {
            Ok(Response::from_status(StatusCode::NOT_FOUND)
                .with_body_text_plain("Not Found\n"))
        }
    };

    match route_result {
        Ok(mut resp) => {
            resp.set_header(header::SERVER, "Fastly-Compute-Router");
            Ok(resp)
        }
        Err(e) => {
            eprintln!("Error routing request: {}", e);
            Ok(Response::from_status(StatusCode::BAD_GATEWAY)
                .with_body_text_plain("Backend Error\n"))
        }
    }
}

fn route_to_api(mut req: Request) -> Result<Response, Error> {
    req.set_header("X-Forwarded-Host", req.get_header_str("Host").unwrap_or(""));
    req.set_header("X-Router", "Fastly-Compute");
    
    let beresp = req.send(BACKEND_API)?;
    
    Ok(beresp)
}

fn route_to_auth(mut req: Request) -> Result<Response, Error> {
    req.set_header("X-Forwarded-Host", req.get_header_str("Host").unwrap_or(""));
    req.set_header("X-Auth-Router", "true");
    
    let beresp = req.send(BACKEND_AUTH)?;
    
    Ok(beresp)
}

fn route_to_static(mut req: Request) -> Result<Response, Error> {
    req.set_header("X-Forwarded-Host", req.get_header_str("Host").unwrap_or(""));
    
    let mut beresp = req.send(BACKEND_STATIC)?;
    
    if beresp.get_status() == StatusCode::OK {
        beresp.set_header(header::CACHE_CONTROL, "public, max-age=3600");
    }
    
    Ok(beresp)
}